    buf.end = (u_char *)data + size;
    buf.pos = buf.start;
    buf.free = buf.end;

    if (nxt_http_parse_request(&rp, &buf) != NXT_DONE) {
        goto failed;
    }

    r_h1p_peer = nxt_mp_zget(mp, sizeof(nxt_http_request_t));

    if (r_h1p_peer == NULL) {
        goto failed;
    }

    nxt_http_fields_process(rp.fields, &nxt_h1p_peer_fields_hash, r_h1p_peer);

failed:

    nxt_mp_destroy(mp);

    return 0;
}

