	widechar *inputText = malloc((size*16+1)*sizeof(widechar));
	int len = (int)_lou_extParseChars(mutable_data, inputText);
	free(mutable_data);
	if (len <= 0) {
		free(inputText);
		return -1;
	}

	assert(len <= (size*16));
	inputLen = len;
	outputLen = len*16;
	widechar *outputText = malloc((outputLen+1)*sizeof(widechar));
