	if (dwfl_core_file_report(dwfl, core, NULL) < 0)
		goto cleanup;
	if (dwfl_report_end(dwfl, NULL, NULL) != 0)
		goto cleanup;

cleanup:
	dwfl_end(dwfl);
	elf_end(core);
	close(fd);
	unlink(name);
	return 0;
}

