    uint8_t zero = 0;
    for (size_t i = 0; i < expectedSize; i += sizeof(zero)) {
        if (fwrite(&zero, sizeof(zero), 1, fp) != 1) {
            error("Error writing\n");
        }
    }
    fclose(fp);
    return 0;
}

