    int main(int argc, char *argv[]) {                                         \
        if (argc == 3) {                                                       \
            if (strcmp(argv[1], "--generate") != 0) {                          \
                error(                                                         \
                    "Invalid option (should be --generate, otherwise look at " \
                    "aflHarness.h to see options)");                           \
            }                                                                  \
            return generateTestCase(argv[2], expectedSize);                    \
        }                                                                      \
        if (argc != 2) {                                                       \
